insert into public.matchday_bet_lines (id, game_week_id, proposal_entity_id, sort_order, label, schedule_note, ai_reasoning, form_id, form_note, market_id, odds)
values
  ('arsenal-bournemouth-arsenal-dnb', 'md-32', 'md-32:defensive', 0, 'Arsenal v Bournemouth: Arsenal Draw No Bet', 'Sat 11 Apr, 12:30 BST', 'Arsenal won four of their last five league matches, while Bournemouth came in off one win and three draws in five, so draw protection fits the safer opener.', 'arsenal-bournemouth-arsenal-dnb:form', 'Arsenal last 5 league matches: 4W 0D 1L. Bournemouth last 5 league matches: 1W 3D 1L.', 'arsenal-bournemouth-arsenal-dnb', null),
  ('liverpool-fulham-over-1-5', 'md-32', 'md-32:defensive', 1, 'Liverpool v Fulham: Over 1.5 Goals', 'Sat 11 Apr, 17:30 BST', 'Liverpool scored nine across recent wins over West Ham and Wolves, and Fulham''s last four league and cup games still gave a two-goal floor enough to support a safer totals angle.', 'liverpool-fulham-over-1-5:form', 'Liverpool recent scoring form: 9 goals across their latest two wins. Fulham recent match trend: their last 4 league and cup games all still supported a 2+ goal script.', 'liverpool-fulham-over-1-5', null),
  ('chelsea-man-city-over-1-5', 'md-32', 'md-32:defensive', 2, 'Chelsea v Man City: Over 1.5 Goals', 'Sun 12 Apr, 16:30 BST', 'Chelsea''s last five across league and Europe produced 20 total goals and City''s recent run mixed 10 scored with 8 conceded, so a low goals line is the safer way into the fixture.', 'chelsea-man-city-over-1-5:form', 'Chelsea recent 5 across league and Europe: 20 total match goals. Man City recent run: 10 scored and 8 conceded.', 'chelsea-man-city-over-1-5', null),
  ('arsenal-bournemouth-arsenal-win', 'md-32', 'md-32:neutral', 0, 'Arsenal v Bournemouth: Arsenal to Win', 'Sat 11 Apr, 12:30 BST', 'Arsenal''s recent league wins over Chelsea, Brighton and Everton give the home win enough form support to add upside without jumping straight to a margin play.', 'arsenal-bournemouth-arsenal-win:form', 'Arsenal last 5 league matches: 4W 0D 1L. Bournemouth last 5 league matches: 1W 3D 1L.', 'arsenal-bournemouth-arsenal-win', null),
  ('liverpool-fulham-liverpool-win', 'md-32', 'md-32:neutral', 1, 'Liverpool v Fulham: Liverpool to Win', 'Sat 11 Apr, 17:30 BST', 'Liverpool won three of their last four league matches before the break and carried the clearer scoring edge into a meeting with a Fulham side that had one win in four league and cup games.', 'liverpool-fulham-liverpool-win:form', 'Liverpool recent form: 3 wins from their last 4 league matches. Fulham recent form: 1 win from their last 4 league and cup games.', 'liverpool-fulham-liverpool-win', null),
  ('chelsea-man-city-btts', 'md-32', 'md-32:neutral', 2, 'Chelsea v Man City: Both Teams To Score', 'Sun 12 Apr, 16:30 BST', 'Chelsea have both scored and conceded heavily in recent league and European matches, while City''s recent 2-2 with Forest keeps a BTTS script live here.', 'chelsea-man-city-btts:form', 'Chelsea recent profile: goals at both ends have been common across their latest league and European matches. Man City recent profile: the 2-2 draw with Forest kept their BTTS trend live.', 'chelsea-man-city-btts', null),
  ('man-utd-leeds-over-2-5', 'md-32', 'md-32:neutral', 3, 'Man Utd v Leeds United: Over 2.5 Goals', 'Mon 13 Apr, 20:00 BST', 'United''s recent league games have rarely stayed quiet and Leeds still created scoring games against Chelsea and Villa, which keeps the goals angle preferable to a tighter result call.', 'man-utd-leeds-over-2-5:form', 'Man Utd recent trend: their latest league games have stayed open. Leeds recent trend: matches against Chelsea and Villa still produced enough attacking action for a 3+ goal angle.', 'man-utd-leeds-over-2-5', null),
  ('arsenal-bournemouth-arsenal-minus-1', 'md-32', 'md-32:aggressive', 0, 'Arsenal v Bournemouth: Arsenal -1 Handicap', 'Sat 11 Apr, 12:30 BST', 'Arsenal''s stronger run of league wins and Bournemouth''s recent low-scoring, draw-heavy stretch make the home margin angle viable once the build shifts from protection to profit.', 'arsenal-bournemouth-arsenal-minus-1:form', 'Arsenal last 5 league matches: 4W 0D 1L, strong enough to support a margin play. Bournemouth last 5 league matches: 1W 3D 1L.', 'arsenal-bournemouth-arsenal-minus-1', null),
  ('liverpool-fulham-liverpool-win-over-2-5', 'md-32', 'md-32:aggressive', 1, 'Liverpool v Fulham: Liverpool to Win & Over 2.5 Goals', 'Sat 11 Apr, 17:30 BST', 'Liverpool''s recent scoring spikes, including five against West Ham and three in the cup at Wolves, support combining the home win with a higher goals line for more return.', 'liverpool-fulham-liverpool-win-over-2-5:form', 'Liverpool recent form: 3 wins from their last 4 league matches, with scoring spikes in recent victories. Fulham recent games still carry enough goal volume to support a win-plus-goals builder.', 'liverpool-fulham-liverpool-win-over-2-5', null),
